361	// Get the last recorded weight for an exercise
362	function getLastWeight(exerciseName) {
363	  const log = loadLog();
364	  let lastWeight = null;
365	  let lastDay = 0;
366	
367	  for (const key in log) {
368	    if (log[key].exercise === exerciseName && log[key].day > lastDay && isValidWeight(log[key].weight)) {
369	      lastWeight = log[key].weight;
370	      lastDay = log[key].day;
371	    }
372	  }
373	
374	  return lastWeight;
375	}
