377	// Get suggested weight with weekly progression logic
378	function getSuggestedWeight(exerciseName, startingWeight, increment = 5) {
379	  const log = loadLog();
380	  const currentWeek = Math.floor((currentState.globalDay - 1) / 7) + 1;
381	
382	  // Find last logged weight for this exercise (must have a valid weight)
383	  let lastEntry = null;
384	  for (const key in log) {
385	    if (log[key].exercise === exerciseName && isValidWeight(log[key].weight)) {
386	      if (!lastEntry || log[key].timestamp > lastEntry.timestamp) {
387	        lastEntry = log[key];
388	      }
389	    }
390	  }
391	
392	  if (!lastEntry) {
393	    return startingWeight; // First time or no valid weight - use starting weight
394	  }
395	
396	  const lastWeek = Math.floor((lastEntry.day - 1) / 7) + 1;
397	
398	  if (currentWeek > lastWeek) {
399	    // New week - suggest progression
400	    return Math.min(lastEntry.weight + increment, 80); // Cap at 80lbs
401	  }
402	
403	  return lastEntry.weight; // Same week - same weight
404	}
