406	// Increment weight for an exercise
407	function incrementWeight(exerciseKey, increment = 5) {
408	  const input = document.querySelector(`input[data-key="${exerciseKey}"]`);
409	  if (!input) return;
410	
411	  let currentValue = parseFloat(input.value) || parseFloat(input.placeholder) || 5;
412	  const newValue = Math.min(currentValue + increment, 80); // Cap at 80lbs
413	  input.value = newValue;
414	
415	  // Trigger save
416	  saveWeightInput(input);
417	}
