423	
424	  let currentValue = parseFloat(input.value) || parseFloat(input.placeholder) || 10;
425	  const newValue = Math.max(currentValue - increment, 5); // Min 5lbs
426	  input.value = newValue;
427	
428	  // Trigger save
429	  saveWeightInput(input);
